import React from 'react';
import { useCurrentFrame, useVideoConfig, interpolate, spring } from 'remotion';
import { SPRING_SMOOTH } from '../../../lib/motion';
import { PlacementBox, resolveSize } from '../../../lib/canvas';
import { trackingInSchema, type TrackingInProps } from './schema';

export { trackingInSchema, type TrackingInProps };

/**
 * The text begins spread wide and contracts to its resting tracking on the
 * house spring, fading (and optionally sharpening from a soft blur) as it
 * settles. A confident, cinematic title entrance — no overshoot.
 *
 * @example
 * <TrackingIn text="ONDA" />
 */
export const TrackingIn: React.FC<TrackingInProps> = ({
  text, delay, duration, color, fromTracking, tracking, blur,
  fontSize, size, fontFamily, fontWeight, lineHeight, align, placement,
}) => {
  const frame = useCurrentFrame();
  const { fps, width, height } = useVideoConfig();
  const local = Math.max(0, frame - delay);
  const resolvedFontSize = size ? resolveSize(size, { width, height }) : fontSize;

  const progress = spring({ frame: local, fps, config: SPRING_SMOOTH, durationInFrames: duration });
  const opacity = interpolate(progress, [0, 1], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const ls = interpolate(progress, [0, 1], [fromTracking, tracking], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
  const blurPx = blur ? interpolate(progress, [0, 1], [8, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' }) : 0;

  return (
    <PlacementBox placement={placement}>
      <div
        style={{
          opacity,
          color,
          fontSize: resolvedFontSize,
          fontFamily,
          fontWeight,
          lineHeight,
          textAlign: align,
          letterSpacing: `${ls}em`,
          filter: blurPx ? `blur(${blurPx}px)` : undefined,
        }}
      >
        {text}
      </div>
    </PlacementBox>
  );
};

import { z } from 'zod';
import { DURATION } from '../../../lib/motion';
import { placementSchema, sizeRoleSchema } from '../../../lib/canvas-schemas';

/** Zod schema for {@link TrackingIn} props. */
export const trackingInSchema = z.object({
  /** Discriminator literal — matches this entry's registry slug. Auto-populated when omitted. */
  kind: z.literal('tracking-in').default('tracking-in'),
  /** The text to settle in. */
  text: z.string().default('Onda'),
  /** Frames before the entrance starts. */
  delay: z.number().int().min(0).default(0),
  /** Frames until the text settles. */
  duration: z.number().int().min(1).default(DURATION.slow),
  /** Text color. Defaults to `--onda-text`. */
  color: z.string().default('var(--onda-text, #F2F2F4)'),
  /** Starting letter-spacing in em — the text begins spread wide and contracts. */
  fromTracking: z.number().default(0.5),
  /** Resting letter-spacing in em. */
  tracking: z.number().default(-0.02),
  /** Start the text slightly blurred and sharpen as it settles. */
  blur: z.boolean().default(true),
  /** Pixels. Wins over `size` if both are passed. */
  fontSize: z.number().default(96),
  /** Semantic typography role — canvas-aware pixels. */
  size: sizeRoleSchema.optional(),
  /** Onda display font. Never default to Inter / Arial / system. */
  fontFamily: z.string().default('var(--onda-font-display, "Clash Display", sans-serif)'),
  /** Font weight. */
  fontWeight: z.number().default(600),
  /** Unitless line height. */
  lineHeight: z.number().default(1.1),
  /** Text alignment. */
  align: z.enum(['left', 'center', 'right']).default('center'),
  /** Where on the canvas this sits. */
  placement: placementSchema.optional(),
});

/** Inferred props for {@link TrackingIn}. */
export type TrackingInProps = z.infer<typeof trackingInSchema>;
